/*
 * Extract structured lead data from raw email body.
 * Input: { emailId, from, subject, body, receivedAt, userId? }
 * Output: lead fields ready for POST /api/leads
 */
const input = $input.item.json;
const body   = input.body    || '';
const subject = input.subject || '';
const fromAddr = input.from   || '';

function extract(pattern, text, group) {
  const m = text.match(pattern);
  return m ? m[group || 1].trim() : '';
}

// ─── Customer name ───────────────────────────────────────────────────────────
const customerName =
  extract(/(?:name|customer|client|contact)\s*[:–-]\s*([A-Z][\w\s'-]{2,40})/i, body) ||
  extract(/^([A-Z][a-z]+ [A-Z][a-z]+(?:\s[A-Z][a-z]+)?)/m, body) ||
  extract(/([A-Z][a-z]+ [A-Z][a-z]+)\s*(?:would like|wants to|is looking)/i, body) ||
  'Unknown';

// ─── Email ────────────────────────────────────────────────────────────────────
const customerEmail =
  extract(/(?:email|e-mail)\s*[:–-]\s*([\w.+%-]+@[\w.-]+\.[a-zA-Z]{2,})/i, body) ||
  extract(/([\w.+%-]+@[\w.-]+\.[a-zA-Z]{2,})/i, body) ||
  (() => { const m = fromAddr.match(/<([^>]+)>/); return m ? m[1] : fromAddr; })();

// ─── Phone ───────────────────────────────────────────────────────────────────
const customerPhone =
  extract(/(?:phone|tel|mobile|call|number)\s*[:–-]\s*([+\d][\d\s().+-]{6,20})/i, body) ||
  extract(/(?<![\w@])([+]?(?:\d[\s.-]?){9,14}\d)(?![\w@])/i, body);

// ─── From address ─────────────────────────────────────────────────────────────
const fromAddress =
  extract(/(?:from|moving from|collecting from|pickup address|collection address|from address)\s*[:–-]\s*([^\n]{5,100})/i, body) ||
  extract(/(?:from|origin)\s*[:–-]\s*([\w\s,]+(?:road|street|avenue|lane|drive|close|way|place|crescent|court|terrace|grove|park|gardens|square|hill|view|rise|walk)[\w\s,]*)/i, body);

// ─── To address ───────────────────────────────────────────────────────────────
const toAddress =
  extract(/(?:to|moving to|delivering to|delivery address|destination address|to address)\s*[:–-]\s*([^\n]{5,100})/i, body) ||
  extract(/(?:to|destination)\s*[:–-]\s*([\w\s,]+(?:road|street|avenue|lane|drive|close|way|place|crescent|court|terrace|grove|park|gardens|square|hill|view|rise|walk)[\w\s,]*)/i, body);

// ─── Moving date ──────────────────────────────────────────────────────────────
const movingDate =
  extract(/(?:date|moving date|removal date|move date|date of move)\s*[:–-]?\s*(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4})/i, body) ||
  extract(/(?:date|moving date|removal date)\s*[:–-]?\s*(\d{4}-\d{2}-\d{2})/i, body) ||
  extract(/(\d{1,2}(?:st|nd|rd|th)?\s+(?:January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{4})/i, body);

// ─── Services ─────────────────────────────────────────────────────────────────
const services = [];
if (/packing|pack\b/i.test(body))       services.push('Packing');
if (/unpack/i.test(body))              services.push('Unpacking');
if (/storage/i.test(body))             services.push('Storage');
if (/assemble|disassemble|assembly/i.test(body)) services.push('Assembly');
if (/clean/i.test(body))              services.push('Cleaning');
if (/piano/i.test(body))              services.push('Piano Moving');
if (/man.*van|van.*man/i.test(body))   services.push('Man and Van');
if (/office|commercial/i.test(body))   services.push('Office Move');

// ─── Confidence score ─────────────────────────────────────────────────────────
let confidence = 20;
if (customerName !== 'Unknown') confidence += 15;
if (customerEmail)   confidence += 15;
if (customerPhone)   confidence += 10;
if (fromAddress)     confidence += 15;
if (toAddress)       confidence += 15;
if (movingDate)      confidence += 10;

// Boost for known lead-source senders
const knownSources = [
  'comparemymove.com', 'anyvan.com', 'checkatrade.com',
  'rated.people', 'trustpilot', 'bark.com', 'quotemyremoval.co.uk'
];
if (knownSources.some(src => fromAddr.toLowerCase().includes(src))) confidence = Math.min(confidence + 20, 95);

return [{
  json: {
    userId:           input.userId || '',
    source:           'email',
    rawEmailId:       input.emailId || '',
    rawEmailSubject:  subject,
    rawEmailFrom:     fromAddr,
    customerName,
    customerEmail,
    customerPhone:    customerPhone || '',
    fromAddress:      fromAddress  || '',
    toAddress:        toAddress    || '',
    movingDate:       movingDate   || '',
    services,
    notes:            body.substring(0, 1000),
    confidence,
    status:           'new'
  }
}];
